// src/pages/ApplyLeave.js
import React, { useState } from 'react';
import { useApp } from '../context/AppContext';

export default function ApplyLeave() {
  const { staff, currentUser, leaveRequests, setLeaveRequests } = useApp();
  const [fromDate, setFromDate] = useState('');
  const [toDate, setToDate] = useState('');
  const [reason, setReason] = useState('');
  const [selectedStaff, setSelectedStaff] = useState('');

  const freeStaff = staff.filter(s => s.isFree); // free staff

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!selectedStaff) {
      alert('Select a free staff to assign');
      return;
    }

    const newLeave = {
      id: Date.now(),
      applicant: currentUser.name,      // jisne apply kiya
      assignedTo: selectedStaff.name,   // free staff ko bheja
      status: 'Pending',
      approvedBy: null,
      reason,
      fromDate,
      toDate,
      createdAt: new Date().toLocaleString()
    };

    setLeaveRequests([...leaveRequests, newLeave]);
    setFromDate('');
    setToDate('');
    setReason('');
    setSelectedStaff('');
    alert('Leave request submitted successfully!');
  };

  return (
    <div style={{ padding: 30, maxWidth: 600, margin: '0 auto' }}>
      <h2>Apply Leave</h2>
      <form onSubmit={handleSubmit}>
        <label>From Date:</label>
        <input type="date" value={fromDate} onChange={e => setFromDate(e.target.value)} required />
        <label>To Date:</label>
        <input type="date" value={toDate} onChange={e => setToDate(e.target.value)} required />
        <label>Reason:</label>
        <textarea value={reason} onChange={e => setReason(e.target.value)} required />
        <label>Assign To (Free Staff):</label>
        <select value={selectedStaff.name || ''} onChange={e => setSelectedStaff(freeStaff.find(f => f.id == e.target.value))} required>
          <option value="">-- Select Staff --</option>
          {freeStaff.map(f => (
            <option key={f.id} value={f.id}>{f.name}</option>
          ))}
        </select>
        <button type="submit">Submit Leave</button>
      </form>
    </div>
  );
}
